@dataclass
class ReportJSON:
    purpose: str
    one_liner: str
    modules: List[dict] = field(default_factory=list)
    incomplete_features: List[str] = field(default_factory=list)
    dependency_graph: str = ""


_STDLIB_PREFIXES = {
    "__future__", "abc", "argparse", "ast", "asyncio", "base64", "builtins",
    "collections", "contextlib", "copy", "csv", "dataclasses", "datetime",
    "decimal", "enum", "errno", "fnmatch", "functools", "glob", "hashlib",
    "heapq", "html", "http", "importlib", "inspect", "io", "ipaddress",
    "itertools", "json", "logging", "math", "mimetypes", "operator", "os",
    "pathlib", "pickle", "pkgutil", "platform", "pprint", "queue", "random",
    "re", "secrets", "shlex", "shutil", "signal", "socket", "sqlite3",
    "ssl", "stat", "string", "struct", "subprocess", "sys", "tempfile",
    "textwrap", "threading", "time", "tomllib", "traceback", "types",
    "typing", "unittest", "urllib", "uuid", "warnings", "weakref", "xml",
    "zipfile",
}

_THIRD_PARTY_PREFIXES = {
    "anyio", "click", "dotenv", "faiss", "fastapi", "git", "h11", "httpx",
    "httpcore", "jiter", "jsonpatch", "jsonpointer", "langchain",
    "langchain_core", "langchain_openai", "langgraph", "langsmith",
    "numpy", "openai", "orjson", "ormsgpack", "pydantic", "pydantic_core",
    "requests", "regex", "smmap", "sniffio", "sse_starlette", "starlette",
    "tenacity", "tiktoken", "tree_sitter", "tree_sitter_python", "uvicorn",
    "websockets", "yaml", "pyyaml", "tqdm", "certifi",
}

_EXTERNAL_PREFIXES = _STDLIB_PREFIXES | _THIRD_PARTY_PREFIXES

_MAX_NODES = 20


def _is_internal_module(name: str) -> bool:
    if not name:
        return False
    return name.split(".")[0] not in _EXTERNAL_PREFIXES


def _mermaid_id(name: str) -> str:
    return "n_" + re.sub(r"[^A-Za-z0-9_]", "_", name)


def build_mermaid_graph(symbol_map: dict) -> str:
    internal = sorted({m for m in symbol_map.keys() if _is_internal_module(m)})

    truncated = False
    if len(internal) > _MAX_NODES:
        internal = internal[:_MAX_NODES]
        truncated = True

    internal_set = set(internal)
    edges: List[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for module in internal:
        parts = module.split(".")
        for i in range(1, len(parts)):
            parent = ".".join(parts[:i])
            if parent in internal_set:
                edge = (parent, module)
                if edge not in seen:
                    edges.append(edge)
                    seen.add(edge)

    lines = ["graph LR"]
    declared: set[str] = set()
    for src, dst in edges:
        if src not in declared:
            lines.append(f'    {_mermaid_id(src)}["{src}"]')
            declared.add(src)
        if dst not in declared:
            lines.append(f'    {_mermaid_id(dst)}["{dst}"]')
            declared.add(dst)
        lines.append(f"    {_mermaid_id(src)} --> {_mermaid_id(dst)}")
    for module in internal:
        if module not in declared:
            lines.append(f'    {_mermaid_id(module)}["{module}"]')
            declared.add(module)

    if truncated:
        lines.append(f'    %% truncated to {_MAX_NODES} nodes')

    return "\n".join(lines)

